import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Tenant Settings — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant Settings — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/tenant-settings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant Settings — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/tenant-settings"}]]},"headers":[],"relativePath":"deployment/tenant-settings.md","filePath":"deployment/tenant-settings.md","lastUpdated":1784403917000}'),i={name:"deployment/tenant-settings.md"};function s(r,e,d,c,l,p){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="tenant-settings-—-production-guide" tabindex="-1">Tenant Settings — Production Guide <a class="header-anchor" href="#tenant-settings-—-production-guide" aria-label="Permalink to &quot;Tenant Settings — Production Guide&quot;">​</a></h1><h2 id="deploy-checklist" tabindex="-1">Deploy checklist <a class="header-anchor" href="#deploy-checklist" aria-label="Permalink to &quot;Deploy checklist&quot;">​</a></h2><ol><li>Run migrations (adds <code>type</code> / <code>group</code> on <code>tenant_settings</code>).</li><li>Configure object storage: local <code>FILESYSTEM_DISK=public</code> + <code>php artisan storage:link</code>, or production <code>FILESYSTEM_DISK=s3</code>. Optional: <code>FILESYSTEM_BRANDING_DISK=public</code> so tenant branding under <code>tenants/{id}/branding/…</code> stays on local storage (see <a href="/developer-guide/object-storage">object-storage.md</a>).</li><li>Ensure <code>settings.list</code> / <code>settings.update</code> exist in <code>config/tenant-permissions.php</code> and default role maps. New workspaces receive them via <code>TenantAuthorizationProvisioningService</code> during provisioning. Existing workspaces that need newly added settings permissions receive them via an additive permission <strong>data migration</strong> — not production seeders and not login-time sync.</li><li>Confirm <code>APP_KEY</code> is stable — SMTP passwords are encrypted with Laravel Crypt.</li></ol><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Control</th></tr></thead><tbody><tr><td>Isolation</td><td>Settings scoped by <code>tenant_id</code>; API requires tenancy + tenant auth</td></tr><tr><td>Cross-tenant</td><td>Branding files live under <code>tenants/{uuid}/…</code></td></tr><tr><td>Secrets</td><td><code>mail_password</code> encrypted at rest; API returns <code>********</code></td></tr><tr><td>Central leakage</td><td>Tenant API never exposes Central-only keys (registration, maintenance, billing)</td></tr></tbody></table><h2 id="ops-signals" tabindex="-1">Ops signals <a class="header-anchor" href="#ops-signals" aria-label="Permalink to &quot;Ops signals&quot;">​</a></h2><ul><li>Unexpected Central branding on a tenant SPA usually means no tenant override + public bootstrap fell back correctly.</li><li>Mail from Central From-address on a tenant that expected custom SMTP → check whether <code>mail_host</code> is set for that workspace.</li><li>403 on <code>/api/tenant/v1/settings</code> → missing <code>settings.list</code> / <code>settings.update</code> on the role.</li></ul><h2 id="rollback" tabindex="-1">Rollback <a class="header-anchor" href="#rollback" aria-label="Permalink to &quot;Rollback&quot;">​</a></h2><p>Clearing a tenant override (empty optional branding/mail fields, or deleting the <code>tenant_settings</code> row) restores Central defaults immediately after cache forget (handled by the service).</p>',9)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
